/**
 * Unit tests for issue-docs-requirement hook
 * Tests documentation checklist injection for feature issue/PR commands
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { mockCommonBasic } from '../../fixtures/mock-common.js';

vi.mock('../../../lib/common.js', () => mockCommonBasic());

import { issueDocsRequirement } from '../../../pretool/bash/issue-docs-requirement.js';
import type { HookInput } from '../../../types.js';
import { createTestContext } from '../../fixtures/test-context.js';

function makeInput(command: string): HookInput {
  return {
    tool_name: 'Bash',
    session_id: 'test-session-123',
    project_dir: '/test/project',
    tool_input: { command },
  };
}

let ctx: ReturnType<typeof createTestContext>;

describe('issue-docs-requirement', () => {
  beforeEach(() => {
    ctx = createTestContext();
    vi.clearAllMocks();
  });

  // --- Silent cases ---

  it('returns silent success for non-gh commands', () => {
    const result = issueDocsRequirement(makeInput('ls -la'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
    expect(result.hookSpecificOutput).toBeUndefined();
  });

  it('returns silent success for npm install', () => {
    const result = issueDocsRequirement(makeInput('npm install'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  it('returns silent success for gh issue close without feat label', () => {
    const result = issueDocsRequirement(makeInput('gh issue close 42 --label bug'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
    expect(result.hookSpecificOutput).toBeUndefined();
  });

  it('returns silent success for gh pr merge without feature mention', () => {
    const result = issueDocsRequirement(makeInput('gh pr merge 10'), ctx);

    expect(result.continue).toBe(true);
    expect(result.suppressOutput).toBe(true);
  });

  // --- Context injection cases ---

  it('returns docs checklist for gh issue close with --label feat', () => {
    const result = issueDocsRequirement(makeInput('gh issue close 42 --label feat'), ctx);

    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.additionalContext).toContain('Documentation checklist');
    expect(result.hookSpecificOutput?.additionalContext).toContain('README');
    expect(result.hookSpecificOutput?.additionalContext).toContain('JSDoc');
    expect(result.hookSpecificOutput?.additionalContext).toContain('CHANGELOG');
  });

  it('returns docs checklist for gh pr merge with "feature" in command', () => {
    const result = issueDocsRequirement(makeInput('gh pr merge feature/new-api'), ctx);

    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.additionalContext).toContain('Documentation checklist');
    expect(result.hookSpecificOutput?.additionalContext).toContain('usage examples');
  });

  it('returns docs checklist for gh issue close with "feat" in command text', () => {
    const result = issueDocsRequirement(makeInput('gh issue close feat/login-flow'), ctx);

    expect(result.continue).toBe(true);
    expect(result.hookSpecificOutput?.additionalContext).toContain('Feature completion detected');
  });

  it('logs permission and hook event on feature detection', () => {
    issueDocsRequirement(makeInput('gh issue close 42 --label feat'), ctx);

    expect(ctx.logPermission).toHaveBeenCalledWith('allow', 'Feature docs reminder', expect.any(Object));
    expect(ctx.log).toHaveBeenCalledWith('issue-docs-requirement', 'Feature completion - docs reminder');
  });
});
